vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    vec4 N1 = texture(sampler_pw_noise_lq, vUv*uTexSize.xy*texsize_noise_lq.zw+rand_frame.xy);
    vec4 N2 = texture(sampler_pw_noise_lq, vUv*uTexSize.xy*texsize_noise_lq.zw*2+rand_frame.xy);
    N1 -= 0.5; N2 -= 0.5;

    vec2 uv1 = vUv + N1.xy*uTexSize.zw*2;
    vec2 uv2 = vUv + N2.xy*uTexSize.zw*2;

    ret = texture(sampler_main, uv1).xyz;
    ret += texture(sampler_main, uv2).xyz;
    ret *= 0.5;
    ret *= 1.15; //gamma
